//------------------------------------------------------------------------------
// fifo_single_clock_reg_v2.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Single-clock FIFO buffer implementation, also known as "queue"
//
//  I`ve made two variants of fifo_single_clock_reg module - v1 and v2
//  Both variants are valid, both operate identically from an outside observer`s
//    view. Only internal r/w pointers operation is different.
//
//  Features:
//  - single clock operation
//  - configurable depth and data width
//  - one write- and one read- port in "FWFT" or "normal" mode
//  - protected against overflow and underflow
//  - simultaneous read and write operations supported BUT:
//        only read will happen if simultaneous rw from full fifo
//        only write will happen if simultaneous rw from empty fifo
//        Always honor empty and full flags!
//  - (new!) optional fifo contents initialization
//
//  See also "lifo.sv" module for similar LIFO buffer implementation


/* --- INSTANTIATION TEMPLATE BEGIN ---

fifo_single_clock_reg_v2 #(
  .FWFT_MODE( "TRUE" ),
  .DEPTH( 8 ),
  .DATA_W( 32 ),

  // optional initialization
  .INIT_FILE( "fifo_single_clock_reg_v2_init.svh" ),
  .INIT_CNT( 10 )
) FF1 (
  .clk( clk ),
  .nrst( 1'b1 ),

  .w_req(  ),
  .w_data(  ),

  .r_req(  ),
  .r_data(  ),

  .cnt(  ),
  .empty(  ),
  .full(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module fifo_single_clock_reg_v2 #( parameter

  FWFT_MODE = "TRUE",             // "TRUE"  - first word fall-trrough" mode
                                  // "FALSE" - normal fifo mode
  DEPTH = 8,                      // max elements count == DEPTH, DEPTH MUST be power of 2
  DEPTH_W = clogb2(DEPTH)+1,      // elements counter width, extra bit to store
                                  // "fifo full" state, see cnt[] variable comments

  DATA_W = 32,                    // data field width

  // optional initialization
  USE_INIT_FILE = "FALSE",        // "TRUE"  - uses special filethat provides init data
                                  // "FALSE" - initializes with '0
  INIT_CNT = '0                   // sets desired initial cnt[]
)(
  input clk,
  input nrst,                     // inverted reset

  // input port
  input w_req,
  input [DATA_W-1:0] w_data,

  // output port
  input r_req,
  output logic [DATA_W-1:0] r_data,

  // helper ports
  output logic [DEPTH_W-1:0] cnt,
  output logic empty,
  output logic full,

  output logic fail
);

  // fifo data
  logic [DEPTH-1:0][DATA_W-1:0] data;

  // read and write pointers
  logic [DEPTH_W-1:0] w_ptr;
  logic [DEPTH_W-1:0] r_ptr;

  // fofo initialization
  // Modelsim gives suppressable error here
  // "(vlog-7061) Variable 'data' driven in an always_ff block, may not be driven by any other process"
  generate
    initial begin
      if( USE_INIT_FILE ) begin
        `include "fifo_single_clock_reg_v2_init.svh"
        w_ptr[DEPTH_W-1:0] <= INIT_CNT[DEPTH_W-1:0];
        r_ptr[DEPTH_W-1:0] <= '0;
        cnt[DEPTH_W-1:0] <= INIT_CNT[DEPTH_W-1:0];
      end else begin
        data <= '0;
        w_ptr[DEPTH_W-1:0] <= '0;
        r_ptr[DEPTH_W-1:0] <= '0;
        cnt[DEPTH_W-1:0] <= '0;
      end
    end // initial
  endgenerate


  // data output buffer for normal fifo mode
  logic [DATA_W-1:0] data_buf = '0;

  always_ff @(posedge clk) begin
    integer i;
    if ( ~nrst ) begin
      if( USE_INIT_FILE ) begin
        `include "fifo_single_clock_reg_v2_init.svh"
        w_ptr[DEPTH_W-1:0] <= INIT_CNT[DEPTH_W-1:0];
        r_ptr[DEPTH_W-1:0] <= '0;
        cnt[DEPTH_W-1:0] <= INIT_CNT[DEPTH_W-1:0];
      end else begin
        data <= '0;
        w_ptr[DEPTH_W-1:0] <= '0;
        r_ptr[DEPTH_W-1:0] <= '0;
        cnt[DEPTH_W-1:0] <= '0;
      end
      data_buf[DATA_W-1:0] <= '0;
    end else begin
      unique case ({w_req, r_req})
        2'b00: ; // nothing

        2'b01: begin  // reading out
          if( ~empty ) begin
            r_ptr[DEPTH_W-1:0] <= inc_ptr(r_ptr[DEPTH_W-1:0]);
            cnt[DEPTH_W-1:0] <= cnt[DEPTH_W-1:0] - 1'b1;
            data_buf[DATA_W-1:0] <= data[r_ptr[DEPTH_W-1:0]];
          end
        end

        2'b10: begin  // writing in
          if( ~full ) begin
            w_ptr[DEPTH_W-1:0] <= inc_ptr(w_ptr[DEPTH_W-1:0]);
            data[w_ptr[DEPTH_W-1:0]] <= w_data[DATA_W-1:0];
            cnt[DEPTH_W-1:0] <= cnt[DEPTH_W-1:0] + 1'b1;
          end
        end

        2'b11: begin  // simultaneously reading and writing
          if( empty ) begin
            w_ptr[DEPTH_W-1:0] <= inc_ptr(w_ptr[DEPTH_W-1:0]);
            data[w_ptr[DEPTH_W-1:0]] <= w_data[DATA_W-1:0];
            cnt[DEPTH_W-1:0] <= cnt[DEPTH_W-1:0] + 1'b1;
          end else if( full ) begin
            r_ptr[DEPTH_W-1:0] <= inc_ptr(r_ptr[DEPTH_W-1:0]);
            cnt[DEPTH_W-1:0] <= cnt[DEPTH_W-1:0] - 1'b1;

            data_buf[DATA_W-1:0] <= data[r_ptr[DEPTH_W-1:0]];
          end else begin
            w_ptr[DEPTH_W-1:0] <= inc_ptr(w_ptr[DEPTH_W-1:0]);
            data[w_ptr[DEPTH_W-1:0]] <= w_data[DATA_W-1:0];
            //cnt[DEPTH_W-1:0] <=  // data counter does not change here

            r_ptr[DEPTH_W-1:0] <= inc_ptr(r_ptr[DEPTH_W-1:0]);
            //cnt[DEPTH_W-1:0] <=  // data counter does not change here
            data_buf[DATA_W-1:0] <= data[r_ptr[DEPTH_W-1:0]];
          end
        end
      endcase
    end
  end

  always_comb begin
    empty = ( cnt[DEPTH_W-1:0] == '0 );
    full = ( cnt[DEPTH_W-1:0] == DEPTH );

    if( FWFT_MODE == "TRUE" ) begin    // first-word fall-through mode
      if( ~empty ) begin
        r_data[DATA_W-1:0] = data[r_ptr[DEPTH_W-1:0]];
      end else begin
        r_data[DATA_W-1:0] = '0;
      end
    end else begin    // normal mode
      r_data[DATA_W-1:0] = data_buf[DATA_W-1:0];
    end

    fail = ( empty && r_req ) ||
           ( full && w_req );
  end


  function [DEPTH_W-1:0] inc_ptr (
    input [DEPTH_W-1:0] ptr
  );
    if( ptr[DEPTH_W-1:0] == DEPTH-1 ) begin
      inc_ptr[DEPTH_W-1:0] = '0;
    end else begin
      inc_ptr[DEPTH_W-1:0] = ptr[DEPTH_W-1:0] + 1'b1;
    end
  endfunction

  `include "clogb2.svh"

endmodule

//------------------------------------------------------------------------------
// preview_fifo.sv
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
// Preview FIFO, v2
//
// The module performs just like an ordinany FIFO in show-ahead mode.
// The diffenence is that 0, 1 or 2 words may be written at once.
// Also, 0, 1 or 2 words may be requested at once.
// This gives an opportunity for the reader to "preview" up to 2 future
// fifo words without actually fetching it yet.
//


/* --- INSTANTIATION TEMPLATE BEGIN ---

preview_fifo #(
  .WIDTH( 16 ),
  .DEPTH( 16 )     // must be at least 8
) pf (
  .clk( clk ),
  .nrst( nrst ),

  // input port
  .wrreq(  ),           // 3 bit one-hot
  .id0(  ),             // first word
  .id1(  ),             // secong word

  // output port
  .rdreq(  ),           // 3 bit one-hot
  .od0(  ),             // first word
  .od1(  ),             // second word

  .empty( [1:0] ),      // 2'b00, 2'b10 or 2'b11
  .full( [1:0] ),       // 2'b11, 2'b01 or 2'b00
  .usedw( [USED_W:0] )  // attention to the width!

);

--- INSTANTIATION TEMPLATE END ---*/


module preview_fifo #( parameter
  WIDTH = 32,
  DEPTH = 16,                    // must be at least 8

  USED_W = $clog2(DEPTH)
)(
  input clk,
  input nrst,

  // input port
  input [2:0] wrreq,             // 3'b001 - no write
                                 // 3'b010 - write one word
                                 // 3'b100 - write two words at once
  input [WIDTH-1:0] id0,         // preceding data word
  input [WIDTH-1:0] id1,         // subsequent data word
                                 // both data words are written simultaneously

  // output port
  input [2:0] rdreq,             // 3'b001 - no read
                                 // 3'b010 - read one word
                                 // 3'b100 - read two words at once
  output logic [WIDTH-1:0] od0,  // first data word (preceding)
  output logic [WIDTH-1:0] od1,  // seconfd dadta word (subsequent)

  output [1:0] empty,            // when FIFO has just one word -
                                 //  any of thse bits will be active
                                 // when FIFO has no words -
                                 //  both of these flags will be active
  output [1:0] full,             // "full" flags, logic is similar to "empty"
  output logic[USED_W:0] usedw   // word count, attention to the additional
                                 //  MSB for holding word count when full
);


// *_ptr=0 means that next read or write shoul happen with FIFO0
// *_ptr=1 means that next read or write shoul happen with FIFO1
logic wr_ptr = 1'b0;
logic rd_ptr = 1'b0;

logic [1:0] f_wrreq;
logic [1:0][WIDTH-1:0] f_wrdata;

logic [1:0] f_rdreq;
logic [1:0][WIDTH-1:0] f_rddata;

// underflow and owerflow protection flags
logic w0_valid, w1_valid, w2_valid;
logic r0_valid, r1_valid, r2_valid;
always_comb begin
  w0_valid <= ~full[0];
  w1_valid <= ~full[1];
  w2_valid <= ~|full[1:0];    // write two words is valid
  r0_valid <= ~empty[0];
  r1_valid <= ~empty[1];
  r2_valid <= ~|empty[1:0];   // read two words is valid
end


// writing internal FIFOs ======================================================
always_comb begin
  case( wrreq[2:0] )
    3'b010: begin  // writing one word
      if( wr_ptr ) begin
        f_wrreq[0] <= 1'b0;
        if( w1_valid ) begin  // protecting from overflow
          f_wrreq[1] <= 1'b1;
        end else begin
          f_wrreq[1] <= 1'b0;
        end
      end else begin
        if( w0_valid ) begin  // protecting from overflow
          f_wrreq[0] <= 1'b1;
        end else begin
          f_wrreq[0] <= 1'b0;
        end
        f_wrreq[1] <= 1'b0;
      end // wr_ptr
    end
    3'b100: begin  // writing two words
      if( w2_valid ) begin  // protecting from overflow
        f_wrreq[0] <= 1'b1;
        f_wrreq[1] <= 1'b1;
      end else begin
        f_wrreq[0] <= 1'b0;
        f_wrreq[1] <= 1'b0;
      end
    end
    default: begin  // supports valid "3'b001" case and all invalid cases
      f_wrreq[0] <= 1'b0;
      f_wrreq[1] <= 1'b0;
    end
  endcase

  if( wr_ptr ) begin
    f_wrdata[0][WIDTH-1:0] <= id1[WIDTH-1:0];
    f_wrdata[1][WIDTH-1:0] <= id0[WIDTH-1:0];
  end else begin
    f_wrdata[0][WIDTH-1:0] <= id0[WIDTH-1:0];
    f_wrdata[1][WIDTH-1:0] <= id1[WIDTH-1:0];
  end
end

always_ff @(posedge clk) begin
  if( ~nrst ) begin
    wr_ptr = 1'b0;
  end else begin
    if( wr_ptr ) begin
      if( wrreq[2:0] == 3'b010 && w1_valid ) begin
        wr_ptr = ~wr_ptr;
      end
    end else begin
      if( wrreq[2:0] == 3'b010 && w0_valid ) begin
        wr_ptr = ~wr_ptr;
      end
    end
  end // nrst
end


// reading internal FIFOs ======================================================
always_comb begin
  case( rdreq[2:0] )
    3'b010: begin
      if( rd_ptr ) begin
        f_rdreq[0] <= 1'b0;
        if( r1_valid ) begin  // protecting from underflow
          f_rdreq[1] <= 1'b1;
        end else begin
          f_rdreq[1] <= 1'b0;
        end
      end else begin
        if( r0_valid ) begin  // protecting from underflow
          f_rdreq[0] <= 1'b1;
        end else begin
          f_rdreq[0] <= 1'b0;
        end
        f_rdreq[1] <= 1'b0;
      end
    end
    3'b100: begin
      if( r2_valid ) begin  // protecting from underflow
        f_rdreq[0] <= 1'b1;
        f_rdreq[1] <= 1'b1;
      end else begin
        f_rdreq[0] <= 1'b0;
        f_rdreq[1] <= 1'b0;
      end
    end
    default: begin
      f_rdreq[0] <= 1'b0;
      f_rdreq[1] <= 1'b0;
    end
  endcase

  if( rd_ptr ) begin
    od0[WIDTH-1:0] <= f_rddata[1][WIDTH-1:0];
    od1[WIDTH-1:0] <= f_rddata[0][WIDTH-1:0];
  end else begin
    od0[WIDTH-1:0] <= f_rddata[0][WIDTH-1:0];
    od1[WIDTH-1:0] <= f_rddata[1][WIDTH-1:0];
  end
end

always_ff @(posedge clk) begin
  if( ~nrst ) begin
    rd_ptr = 1'b0;
  end else begin
    if( rd_ptr ) begin
      if( rdreq[2:0] == 3'b010 && r1_valid ) begin
        rd_ptr = ~rd_ptr;
      end
    end else begin
      if( rdreq[2:0] == 3'b010 && r0_valid ) begin
        rd_ptr = ~rd_ptr;
      end
    end
  end // nrst
end

// internal FIFOs itself =======================================================

  logic [1:0][USED_W-2:0] f_usedw_i;
  logic [1:0][USED_W-1:0] f_usedw;

  scfifo #(
    .LPM_WIDTH( WIDTH ),
    .LPM_NUMWORDS( DEPTH/2 ),   // must be at least 4
    .LPM_WIDTHU( USED_W-1 ),
    .LPM_SHOWAHEAD( "ON" ),
    .UNDERFLOW_CHECKING( "ON" ),
    .OVERFLOW_CHECKING( "ON" ),
    .ENABLE_ECC( "FALSE" ),
    .ALLOW_RWCYCLE_WHEN_FULL( "ON" ),
    .USE_EAB( "ON" )
  ) internal_fifo0 (
    .clock( clk ),
    .aclr( 1'b0 ),
    .sclr( ~nrst ),

    .data( f_wrdata[0][WIDTH-1:0] ),
    .wrreq( f_wrreq[0] ),
    .rdreq( f_rdreq[0] ),

    .q( f_rddata[0][WIDTH-1:0] ),
    .empty( empty[0] ),
    .full( full[0] ),
    .usedw( f_usedw_i[0][USED_W-2:0] )
  );

  scfifo #(
    .LPM_WIDTH( WIDTH ),
    .LPM_NUMWORDS( DEPTH/2 ),   // must be at least 4
    .LPM_WIDTHU( USED_W-1 ),
    .LPM_SHOWAHEAD( "ON" ),
    .UNDERFLOW_CHECKING( "ON" ),
    .OVERFLOW_CHECKING( "ON" ),
    .ENABLE_ECC( "FALSE" ),
    .ALLOW_RWCYCLE_WHEN_FULL( "ON" ),
    .USE_EAB( "ON" )
  ) internal_fifo1 (
    .clock( clk ),
    .aclr( 1'b0 ),
    .sclr( ~nrst ),

    .data( f_wrdata[1][WIDTH-1:0] ),
    .wrreq( f_wrreq[1] ),
    .rdreq( f_rdreq[1] ),

    .q( f_rddata[1][WIDTH-1:0] ),
    .empty( empty[1] ),
    .full( full[1] ),
    .usedw( f_usedw_i[1][USED_W-2:0] )
  );

  always_comb begin
    f_usedw[0][USED_W-1:0] = ( full[0] )?
                             ( 1<<(USED_W-1) ):
                             ( {1'b0,f_usedw_i[0][USED_W-2:0]} );
    f_usedw[1][USED_W-1:0] = ( full[1] )?
                             ( 1<<(USED_W-1) ):
                             ( {1'b0,f_usedw_i[1][USED_W-2:0]} );
    usedw[USED_W:0] = f_usedw[0][USED_W-1:0] + f_usedw[1][USED_W-1:0];
  end

endmodule

//------------------------------------------------------------------------------
// fwft_read_ahead_buf.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
// Read ahead buffer for FWFT fifo
//
// The buffer substitutes fifo read port and performs fifo data update at the
//   same clock cycle as r_req, combinationally, for a one cycle earlier than
//   it is expected from standard FWFT fifo
//
// Featires:
//   - effectively increases fifo depth by one word
//   - adds one cycle lateny for empty flag deassertion
//   - does not touch fifo write port and full flag operation logic
//   - hides all combinatorial tinkering inside
//   - allows controlling and analizing fifo read signals from
//                             a single always_ff block, like this:
//
//             always_ff @(posedge clk) begin
//
//                 // read control logic
//                 if( ~empty ) begin        // masking rd_req in always_ff
//                   r_req <= 1'b1;
//                 end else begin
//                   r_req <= 1'b0;
//                 end
//
//                 // getting input data
//                 if( r_req ) begin
//                   new_data[] <= r_data[]; // getting data in always_ff
//                 end
//
//               end
//             end
//

/* --- INSTANTIATION TEMPLATE BEGIN ---

read_ahead_buf #(
  .DATA_W( 32 )
) RB1 (
  .clk(  ),
  .anrst(  ),

  // input fifo interface
  .fifo_r_req(  ),
  .fifo_r_data(  ),
  .fifo_empty(  ),

  // output fifo interface
  .r_req(  ),
  .r_data(  ),
  .empty(  )
);

--- INSTANTIATION TEMPLATE END ---*/

// synopsys translate_off
`define SIMULATION yes
// synopsys translate_on

module read_ahead_buf #( parameter
  DATA_W = 32
)(
  input clk,               // clock
  input anrst,             // inverse reset

  // input fifo interface
  output fifo_r_req,
  input [DATA_W-1:0] fifo_r_data,
  input fifo_empty,

  // output fifo interface
  input r_req,
  output logic [DATA_W-1:0] r_data,
  output logic empty
);


  logic fifo_empty_fall;
  edge_detect fifo_empty_ed (
    .clk( clk ),
    .anrst( anrst ),
    .in( fifo_empty ),
    .rising(  ),
    .falling( fifo_empty_fall ),
    .both(  )
  );

  logic fantom_read;
  logic normal_read;

  logic buf_empty = 1'b1;
  always_ff @(posedge clk or negedge anrst) begin
    if( ~anrst ) begin
      buf_empty = 1'b1;
    end else begin
      if( fantom_read ) begin
        buf_empty <= 1'b0;
      end else if( fifo_empty && r_req ) begin
        buf_empty = 1'b1;
      end
    end
  end

  assign fantom_read = fifo_empty_fall && buf_empty;

  assign normal_read = r_req && ~fifo_empty;

  assign empty = buf_empty ||            // empty falls only after fantom read
                 (r_req && fifo_empty);  // early empty assertion

  assign fifo_r_req = anrst &&
                      (fantom_read || normal_read);

  // prepare combinational signal for soft_latch
  logic latch_req;
  logic [DATA_W-1:0] r_data_latch;
  always_comb begin
    latch_req = ( fantom_read || normal_read ) ||
                ( fifo_empty && r_req );        // buffer depletion

    if( latch_req ) begin
      r_data_latch[DATA_W-1:0] = fifo_r_data[DATA_W-1:0];
    end else begin
      r_data_latch[DATA_W-1:0] = '0;
    end
  end

  soft_latch #(
    .WIDTH( DATA_W )
  ) r_data_latch_b (
    .clk( clk ),
    .anrst( anrst ),
    .latch( latch_req ),
    .in( r_data_latch[DATA_W-1:0] ),
    .out( r_data[DATA_W-1:0] )
  );

endmodule

//------------------------------------------------------------------------------
// fifo_combiner.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Combines / accumulates data words from multiple FIFOs to a single output FIFO.
//  Features three different element enumeration strategies.
//  Reads if ANY input FIFO has data.
//
//  See also fifo_operator.sv
//

/* --- INSTANTIATION TEMPLATE BEGIN ---

fifo_combiner #(
  .WIDTH( 2 ),
  .ENCODER_MODE( "ROUND_ROBIN" ),
  .FWFT_MODE( "TRUE" ),
  .DATA_W( 32 )
) FC1 (
  .clk(  ),
  .nrst(  ),

  .r_empty(  ),
  .r_req(  ),
  .r_data(  ),

  .w_full(  ),  // connect to "almost_full" if FWFT_MODE="FALSE"
  .w_req(  ),
  .w_data(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module fifo_combiner #( parameter

  WIDTH = 2,                     // number of input fifo ports to combine
  WIDTH_W = clogb2(WIDTH),       // input port index width
  ENCODER_MODE = "ROUND_ROBIN",  // "ROUND_ROBIN", "ROUND_ROBIN_PERFORMANCE" or "PRIORITY"
  FWFT_MODE = "TRUE",            // "TRUE"  - first word fall-trrough" mode
                                 // "FALSE" - normal fifo mode
  DATA_W = 32                    // data field width
)(

  input clk,                     // clock
  input nrst,                    // inverted reset

  // input ports
  input [WIDTH-1:0] r_empty,
  output [WIDTH-1:0] r_req,
  input [WIDTH-1:0][DATA_W-1:0] r_data,

  // output port
  input w_full,
  output logic w_req,
  output logic [DATA_W-1:0] w_data
);


  logic enc_valid;
  logic [WIDTH-1:0] enc_filt;
  logic [WIDTH_W-1:0] enc_bin;

  logic [WIDTH-1:0] r_empty_rev;
  reverse_vector #(
    .WIDTH( WIDTH )         // WIDTH must be >=2
  ) empty_rev (
    .in( r_empty[WIDTH-1:0] ),
    .out( r_empty_rev[WIDTH-1:0] )
  );

  generate
    if( ENCODER_MODE == "ROUND_ROBIN" ) begin
      round_robin_enc #(
        .WIDTH( WIDTH )
      ) rr_enc (
        .clk( clk ),
        .nrst( nrst ),
        .id( ~r_empty[WIDTH-1:0] ),
        .od_valid( enc_valid ),
        .od_filt( enc_filt[WIDTH-1:0] ),
        .od_bin( enc_bin[WIDTH_W-1:0] )
      );
    end else if( ENCODER_MODE == "ROUND_ROBIN_PERFORMANCE" ) begin
      round_robin_performance_enc #(
        .WIDTH( WIDTH )
      ) rr_perf_enc (
        .clk( clk ),                  // !!
        .nrst( nrst ),
        .id(~r_empty[WIDTH-1:0] ),
        .od_valid( enc_valid ),
        .od_filt( enc_filt[WIDTH-1:0] ),
        .od_bin( enc_bin[WIDTH_W-1:0] )
      );
    end else if( ENCODER_MODE == "PRIORITY" ) begin
      priority_enc #(
        .WIDTH( WIDTH )   // WIDTH must be >=2
      ) pri_enc (
        .id( ~r_empty[WIDTH-1:0] ),
        .od_valid( enc_valid ),
        .od_filt( enc_filt[WIDTH-1:0] ),
        .od_bin( enc_bin[WIDTH_W-1:0] )
      );
    end // ENCODER_MODE
  endgenerate


  logic r_valid;
  assign r_valid = enc_valid && ~w_full;

  assign r_req[WIDTH-1:0] = {WIDTH{r_valid}} &&
                               enc_filt[WIDTH-1:0];

  // buffering read data
  logic r_valid_d1 = 1'b0;
  logic [WIDTH_W-1:0] enc_bin_d1;
  logic [WIDTH-1:0][DATA_W-1:0] r_data_d1 = '0;
  always_ff @(posedge clk) begin
    if ( ~nrst ) begin
      r_valid_d1 <= 1'b0;
      enc_bin_d1[WIDTH_W-1:0] <= '0;
      r_data_d1[WIDTH-1:0] <= '0;
    end else begin
      r_valid_d1 <= r_valid;
      enc_bin_d1[WIDTH_W-1:0] <= enc_bin[WIDTH_W-1:0];
      r_data_d1[WIDTH-1:0] <= r_data[WIDTH-1:0];
    end
  end

  // routing data to write port
  generate
    if( FWFT_MODE == "TRUE" ) begin

      always_comb begin
        if ( ~nrst ) begin
          w_req = 1'b0;
          w_data[DATA_W-1:0] = '0;
        end else begin
          if( r_valid ) begin
            w_req = 1'b1;
            w_data[DATA_W-1:0] = r_data[enc_bin[WIDTH_W-1:0]][DATA_W-1:0];
          end else begin
            w_req = 1'b0;
            w_data[DATA_W-1:0] = '0;
          end
        end
      end

    end else if( FWFT_MODE == "FALSE" ) begin

      always_comb begin
        if ( ~nrst ) begin
          w_req = 1'b0;
          w_data[DATA_W-1:0] = '0;
        end else begin
          if( r_valid_d1 ) begin
            w_req = 1'b1;
            w_data[DATA_W-1:0] = r_data_d1[enc_bin_d1[WIDTH_W-1:0]][DATA_W-1:0];
          end else begin
            w_req = 1'b0;
            w_data[DATA_W-1:0] = '0;
          end
        end
      end

    end // FWFT_MODE
  endgenerate

  `include "clogb2.svh"

endmodule

//------------------------------------------------------------------------------
// fifo_operator.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
//  Performs custom operation on data words from multiple FIFOs and stores
//  result to a single output FIFO.
//  Reads only if ALL input FIFOs have data.
//  Source code could be easily adapted to apply any operator on input data.
//
//  See also fifo_combiner.sv
//

/* --- INSTANTIATION TEMPLATE BEGIN ---

fifo_operator #(
  .WIDTH( 2 ),
  .FWFT_MODE( "TRUE" ),
  .DATA_W( 32 )
) FO1 (
  .clk(  ),
  .nrst(  ),

  .r_empty(  ),
  .r_req(  ),
  .r_data(  ),

  .w_full(  ),  // connect to "almost_full" if FWFT_MODE="FALSE"
  .w_req(  ),
  .w_data(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module fifo_operator #( parameter

  WIDTH = 2,                     // number of input fifo ports to opeate on
  WIDTH_W = clogb2(WIDTH),       // input port index width
  FWFT_MODE = "TRUE",            // "TRUE"  - first word fall-trrough" mode
                                 // "FALSE" - normal fifo mode
  DATA_W = 32                    // data field width
)(

  input clk,                     // clock
  input nrst,                    // inverted reset

  // input ports
  input [WIDTH-1:0] r_empty,
  output [WIDTH-1:0] r_req,
  input [WIDTH-1:0][DATA_W-1:0] r_data,

  // output port
  input w_full,
  output logic w_req,
  output logic [DATA_W-1:0] w_data
);


  logic r_valid;
  assign r_valid = ~|r_empty && ~w_full;

  assign r_req[WIDTH-1:0] = {WIDTH{r_valid}};

  // buffering read data
  logic r_valid_d1 = 1'b0;
  logic [WIDTH-1:0][DATA_W-1:0] r_data_d1 = '0;
  always_ff @(posedge clk) begin
    if ( ~nrst ) begin
      r_valid_d1 <= 1'b0;
      r_data_d1[WIDTH-1:0] <= '0;
    end else begin
      r_valid_d1 <= r_valid;
      r_data_d1[WIDTH-1:0] <= r_data[WIDTH-1:0];
    end
  end

  // routing data to write port
  generate
    if( FWFT_MODE == "TRUE" ) begin

      always_comb begin
        if ( ~nrst ) begin
          w_req = 1'b0;
          w_data[DATA_W-1:0] = '0;
        end else begin
          if( r_valid ) begin
            w_req = 1'b1;
            w_data[DATA_W-1:0] = operator(r_data);
          end else begin
            w_req = 1'b0;
            w_data[DATA_W-1:0] = '0;
          end
        end
      end

    end else if( FWFT_MODE == "FALSE" ) begin

      always_comb begin
        if ( ~nrst ) begin
          w_req = 1'b0;
          w_data[DATA_W-1:0] = '0;
        end else begin
          if( r_valid_d1 ) begin
            w_req = 1'b1;
            w_data[DATA_W-1:0] = operator(r_data_d1);
          end else begin
            w_req = 1'b0;
            w_data[DATA_W-1:0] = '0;
          end
        end
      end

    end // FWFT_MODE
  endgenerate

  // bitwize OR operator, as an example
  function [DATA_W-1:0] operator (
    input [WIDTH-1:0][DATA_W-1:0] data
  );
    integer i;
    operator[DATA_W-1:0] = '0;
    for( i=0; i<WIDTH; i=i+1 ) begin
      operator[DATA_W-1:0] = operator[DATA_W-1:0] | data[i];
    end
  endfunction

  `include "clogb2.svh"

endmodule

